import axios from 'axios';
import fs from 'fs';

const apiKey = 'your_api_key_here';
const endpoint = 'https://api.qwen3.ai/v1/tts/customvoice';

// Assume voiceEmbedding is obtained from a previous cloning call
const voiceEmbedding = 'base64_encoded_vector_here';

const payload = {
  text: "This is a custom voice example for production use.",
  voice_embedding: voiceEmbedding,
  language: "en-US",
  speed: 1.2,
  pitch: 0.1,
  output_format: "mp3"
};

axios.post(endpoint, payload, {
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json'
  },
  responseType: 'arraybuffer'
}).then(response => {
  // Handle audio data
  const audioBuffer = response.data;
  fs.writeFileSync('custom_output.mp3', audioBuffer);
  console.log('Custom voice audio saved.');
}).catch(error => {
  if (error.response) {
    console.error('API call failed:', error.response.status, error.response.data.toString());
  } else {
    console.error('Network error:', error.message);
  }
});

const express = require('express');
const axios = require('axios');
const app = express();
app.use(express.json());

// Load voice embedding from secure storage
const voiceEmbedding = process.env.VOICE_EMBEDDING;

app.post('/synthesize', async (req, res) => {
  const { text } = req.body;
  if (!text) {
    return res.status(400).send('Text is required');
  }

  try {
    const response = await axios.post('https://api.qwen3.ai/v1/tts/customvoice', {
      text,
      voice_embedding: voiceEmbedding,
      output_format: 'wav',
      speed: 1.0
    }, {
      headers: { 'Authorization': `Bearer ${process.env.API_KEY}` },
      responseType: 'stream',
      timeout: 30000 // 30-second timeout
    });

    res.set('Content-Type', 'audio/wav');
    res.set('X-Request-ID', response.headers['x-request-id']);
    response.data.pipe(res);
  } catch (error) {
    console.error('TTS synthesis failed:', error.message);
    res.status(500).send('Internal server error');
  }
});

app.listen(3000, () => console.log('Server running on port 3000'));
